// src/pages/Home.js (или Table.js)
import React, { useEffect } from 'react';
import { useNavigate } from 'react-router-dom';
import { useAuth } from '../context/AuthContext';
import { useAxios } from 'axios-hooks';

function SIng() {
  const { user, isAuthenticated } = useAuth();
  const navigate = useNavigate();

  // Проверяем авторизацию при загрузке
  useEffect(() => {
    if (!isAuthenticated) {
      navigate('/login');
    }
  }, [isAuthenticated, navigate]);

  // Запрос данных таблицы
  const [{ data, loading, error }] = useAxios(
    '/api/table',
    { 
      useCache: false,
      manual: !isAuthenticated // Не выполнять если не авторизован
    }
  );

  if (!isAuthenticated) {
    return <div>Redirecting to login...</div>;
  }

  if (loading) return <div>Loading table data...</div>;

  if (error) {
    // Если 401 - разлогиниваем
    if (error.response?.status === 401) {
      localStorage.removeItem('user');
      window.location.href = '/login';
      return <div>Session expired, redirecting...</div>;
    }
    return <div>Error: {error.message}</div>;
  }

  return (
    <div>
      <h2>Welcome, {user?.username || 'User'}!</h2>
      <h3>Table Data:</h3>
      {data && (
        <pre>{JSON.stringify(data, null, 2)}</pre>
      )}
    </div>
  );
}

export default Sing;
